      "properties": {
        "deployment_name": {
          "type": "string",
          "description": "The name of the deployment to query (e.g., 'optical-inspection')."
        }
      },
      "required": [
        "deployment_name"
      ]
    },
    "example_output": {
      "replicas": 2,
      "cpu_usage_percentage": 95.5,
      "memory_usage_mb": 450,
      "incoming_qps": 5500
    }
  },
  "get_cluster_constraints": {
    "description": "Fetches the hard limits for scaling, such as maximum and minimum replicas allowed by the cluster quota for the given deployment.",
    "parameters": {
      "type": "object",
      "properties": {
        "deployment_name": {
          "type": "string",
          "description": "The name of the deployment."
        }
      },
      "required": [
        "deployment_name"
      ]
    },
    "example_output": {
      "max_replicas_limit": 5,
      "min_replicas_limit": 1
    }
  },
  "update_replica_count": {
    "description": "Executes a scaling action to set the number of pods for a deployment to a specific value.",
    "parameters": {
      "type": "object",
      "properties": {
        "deployment_name": {
          "type": "string",
          "description": "The name of the deployment to scale."
        },
        "replica_count": {
          "type": "integer",
          "description": "The target number of pods to run."
        }
      },
      "required": [
        "deployment_name",
        "replica_count"
      ]
    },
    "example_output": {
      "status": "success",
      "new_replica_count": 4
    }
  }
